### Addressing Key Requirements

#### 1. N+1 Query Problem — DataLoader Pattern

```ts
// dataloaders.ts
import DataLoader from 'dataloader';

export const createLoaders = (prisma: PrismaClient) => ({
  userLoader: new DataLoader(async (ids: string[]) => {
    const users = await prisma.user.findMany({
      where: { id: { in: ids } }
    });
    return ids.map(id => users.find(u => u.id === id));
  }),

  postLoader: new DataLoader(async (ids: string[]) => {
    const posts = await prisma.post.findMany({
      where: { id: { in: ids } },
      include: { author: true }
    });
    return ids.map(id => posts.find(p => p.id === id));
  }),

  commentCountLoader: new DataLoader(async (postIds: string[]) => {
    const counts = await prisma.comment.groupBy({
      by: ['postId'],
      _count: { id: true },
      where: { postId: { in: postIds } }
    });
    return postIds.map(id => 
      counts.find(c => c.postId === id)?._count.id || 0
    );
  }),

  likeCountLoader: new DataLoader(async (postIds: string[]) => {
    const counts = await prisma.like.groupBy({
      by: ['postId'],
      _count: { id: true },
      where: { postId: { in: postIds }, commentId: null }
    });
    return postIds.map(id => 
      counts.find(c => c.postId === id)?._count.id || 0
    );
  }),

  isLikedByMeLoader: new DataLoader(async (keys: { userId: string, postId: string }[]) => {
    const userId = keys[0].userId; // same for all in batch
    const postIds = [...new Set(keys.map(k => k.postId))];

    const likes = await prisma.like.findMany({
      where: {
        userId,
        postId: { in: postIds },
        commentId: null
      }
    });
    const likedSet = new Set(likes.map(l => l.postId));
    return keys.map(key => likedSet.has(key.postId));
  })
});
```

