### 3. Resolver Implementation & N+1 Solution (DataLoader)

We use **DataLoader** to batch database requests. For example, when fetching a list of posts, we fetch all authors in a single query rather than one per post.

#### Setup: `dataloaderFactory.js`

```javascript
const DataLoader = require('dataloader');
const { PrismaClient } = require('@prisma/client');
const prisma = new PrismaClient();

// Batch load Users by IDs
const createUserLoader = () => {
  return new DataLoader(async (userIds) => {
    const users = await prisma.user.findMany({
      where: { id: { in: [...userIds] } },
    });
    const userMap = new Map(users.map((user) => [user.id, user]));
    return userIds.map((id) => userMap.get(id) || null);
  });
};

// Batch load Post Counts (Likes/Comments)
const createPostStatsLoader = () => {
  return new DataLoader(async (postIds) => {
    // Aggregate query for counts
    const likeCounts = await prisma.like.groupBy({
      by: ['postId'],
      where: { postId: { in: [...postIds] } },
      _count: { id: true },
    });

    const commentCounts = await prisma.comment.groupBy({
      by: ['postId'],
      where: { postId: { in: [...postIds] } },
      _count: { id: true },
    });

    const likeMap = new Map(likeCounts.map((l) => [l.postId, l._count.id]));
    const commentMap = new Map(commentCounts.map((c) => [c.postId, c._count.id]));

    return postIds.map((id) => ({
      likeCount: likeMap.get(id) || 0,
      commentCount: commentMap.get(id) || 0,
    }));
  });
};

// Batch check if current user liked a specific post
const createIsLikedLoader = (currentUserId) => {
  return new DataLoader(async (postIds) => {
    if (!currentUserId) return postIds.map(() => false);

    const likes = await prisma.like.findMany({
      where: {
        userId: currentUserId,
        postId: { in: [...postIds] },
      },
    });
    const likedSet = new Set(likes.map((l) => l.postId));
    return postIds.map((id) => likedSet.has(id));
  });
};

module.exports = (context) => ({
  userLoader: createUserLoader(),
  postStatsLoader: createPostStatsLoader(),
  isLikedLoader: createIsLikedLoader(context.userId), // Context from req
});
```

